/* ============ Small building blocks ============ */

function Logo({ light }: any) {
  return (
    <span
      style={{
        fontFamily: "Georgia, 'Times New Roman', serif",
        letterSpacing: "0.12em",
        color: light ? colors.cream : colors.bg,
        fontSize: 22,
        fontWeight: 400,
      }}
    >
      GANGA PHOTO
    </span>
  );
}

function ApertureBadge({ size = 68 }) {
  const r = size / 2 - 4;
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <circle cx={size / 2} cy={size / 2} r={size / 2 - 2} fill={colors.bg} stroke={colors.gold} strokeWidth="2" />
      <g stroke={colors.goldLight} strokeWidth="2" fill="none">
        {[0, 60, 120, 180, 240, 300].map((deg) => (
          <path
            key={deg}
            d={`M ${size / 2} ${size / 2 - r} A ${r} ${r} 0 0 1 ${size / 2 + r * 0.87} ${size / 2 + r * 0.45}`}
            transform={`rotate(${deg} ${size / 2} ${size / 2})`}
          />
        ))}
      </g>
      <circle cx={size / 2} cy={size / 2} r="3.5" fill={colors.goldLight} />
    </svg>
  );
}

function RiverLines({ width = 500 }) {
  return (
    <svg width={width} height="100" viewBox={`0 0 ${width} 100`} fill="none">
      <path
        d={`M 0,40 Q ${width * 0.16},10 ${width * 0.32},40 T ${width * 0.64},40 T ${width},40`}
        stroke={colors.gold}
        strokeWidth="2.5"
        opacity="0.7"
      />
      <path
        d={`M 0,65 Q ${width * 0.16},35 ${width * 0.32},65 T ${width * 0.64},65 T ${width},65`}
        stroke={colors.sage}
        strokeWidth="1.8"
        opacity="0.5"
      />
      <path
        d={`M 0,88 Q ${width * 0.16},64 ${width * 0.32},88 T ${width * 0.64},88`}
        stroke={colors.sage}
        strokeWidth="1.3"
        opacity="0.35"
      />
    </svg>
  );
}

function PrimaryButton({ children, className = "" }: any) {
  return (
    <button
      className={`rounded-full font-semibold px-7 py-3.5 text-sm transition-transform hover:scale-[1.03] active:scale-95 ${className}`}
      style={{ background: goldGradient, color: colors.bg }}
    >
      {children}
    </button>
  );
}

function SecondaryButton({ children, className = "" }: any) {
  return (
    <button
      className={`rounded-full px-7 py-3.5 text-sm border transition-colors hover:bg-white/5 flex items-center gap-2 ${className}`}
      style={{ borderColor: "#4c5f5c", color: colors.cream }}
    >
      {children}
    </button>
  );
}

